using WebPlatform.Api.Models;

namespace WebPlatform.Api.Dtos;

/**
 * DTO (Data Transfer Object) class, used to transfer data between the
 * client and the server. It is used to define the shape of the data
 * that is sent in the request body when creating or updating a book.
 * The properties of the class exclude Id, as this is automatically
 * generated by the database, and should not be provided by the client.
**/

public class BookRequest
{
    public String? ISBN { get; set; }
    public String Title { get; set; } = "";
    public String Author { get; set; } = "";
    public String Description { get; set; } = "";
    public decimal Price { get; set; }
    public BookCondition Condition { get; set; }
}